use strict;
use warnings;

my $score = 78;
my $grade;

if ($score >= 90) {
    $grade = "AA";
} elsif ($score >= 70) {
    $grade = "BA";
} elsif ($score >= 50) {
    $grade = "CC";
} else {
    $grade = "FF";
}

print "Not: $score -> Harf notu: $grade\n";

# Perl'de switch yerine if-elsif zinciri veya hash kullanilir
my $day = 3;
my %day_names = (1 => "Pazartesi", 2 => "Sali", 3 => "Carsamba");
my $day_name = $day_names{$day} // "Bilinmeyen gun";

print "Gun: $day_name\n";

# Ternary operator
my $number = 7;
my $parity = ($number % 2 == 0) ? "Cift" : "Tek";
print "\n$number sayisi $parity\n";

# unless kullanimi
my $age = 20;
unless ($age < 18) {
    print "\nReşit\n";
}

# Tek satirlik if (postfix)
print "Pozitif sayi\n" if $number > 0;
